	ScoreRes                 int64                      `json:"scoreRes,omitempty"`
	NormalizeRes             int64                      `json:"normalizeRes,omitempty"`
	ScoreStatus              int                        `json:"scoreStatus,omitempty"`
	NormalizeStatus          int                        `json:"normalizeStatus,omitempty"`
